+const SANDBOX_BASE_URL: &str = "https://sandbox.plaid.com";
+const DEVELOPMENT_BASE_URL: &str = "https://development.plaid.com";
+const PRODUCTION_BASE_URL: &str = "https://production.plaid.com";
+const PLAID_HOSTS: &[&str] = &[
